-- Table structure for material_stock
-- ----------------------------
DROP TABLE IF EXISTS `material_stock`;
CREATE TABLE `material_stock`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `material_cd` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '材料CD',
  `material_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '材料名',
  `date` date NOT NULL DEFAULT '2025-01-01' COMMENT '日付',
  `initial_stock` int NULL DEFAULT 0 COMMENT '初期在庫',
  `current_stock` int NULL DEFAULT 0 COMMENT '現在在庫',
  `safety_stock` int NULL DEFAULT 0 COMMENT '安全在庫',
  `planned_usage` int NULL DEFAULT 0 COMMENT '使用数',
  `adjustment_quantity` int NULL DEFAULT 0 COMMENT '調整数',
  `max_stock` int NULL DEFAULT 0 COMMENT '最大在庫',
  `standard_spec` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '規格',
  `unit` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '単位',
  `unit_price` decimal(15, 2) NULL DEFAULT 0.00 COMMENT '単価',
  `pieces_per_bundle` int NULL DEFAULT 0 COMMENT '束当たり本数',
  `long_weight` decimal(15, 2) NULL DEFAULT NULL COMMENT '一本重量',
  `supplier_cd` varchar(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '仕入先CD',
  `supplier_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '仕入先名',
  `lead_time` int NULL DEFAULT 0 COMMENT 'リードタイム(日)',
  `bundle_quantity` int NULL DEFAULT 0 COMMENT '束本数',
  `bundle_weight` decimal(15, 2) NULL DEFAULT 0.00 COMMENT '束重量(kg)',
  `order_quantity` int NULL DEFAULT 0 COMMENT '注文数',
  `order_bundle_quantity` int NULL DEFAULT 0 COMMENT '注文本数',
  `order_amount` decimal(15, 2) NULL DEFAULT 0.00 COMMENT '注文金額',
  `last_updated` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '最終更新日時',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '作成日時',
  `remarks` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '備考',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `idx_material_cd_date`(`material_cd` ASC, `date` ASC) USING BTREE,
  INDEX `idx_material_cd`(`material_cd` ASC) USING BTREE,
  INDEX `idx_supplier_cd`(`supplier_cd` ASC) USING BTREE,
  INDEX `idx_current_stock`(`current_stock` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 10259 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '材料在库表' ROW_FORMAT = Dynamic;

